SELECT q.qc_id AS qcId, q.device_id AS deviceId, q.device_name AS deviceName, q.dept_id AS deptId, q.dept_name AS deptName, q.test_time AS testTime, q.test_type AS testType, q.test_user_id AS testUserId, q.test_user_name AS testUserName, q.device_status AS deviceStatus, q.test_result AS testResult, q.remark AS remark, q.create_time AS createTime, q.update_time AS updateTime FROM ecg_device_quality_control q WHERE q.is_deleted = 0
AND q.device_id = #{req.deviceId}
AND q.test_result = #{statusText}
AND q.test_time >= #{startTime}
AND q.test_time <= #{endTime}
ORDER BY q.test_time DESC, q.qc_id DESC
